#include <bits/stdc++.h>
using namespace std;
const int mod=998244353;
int n,m,k,t,s[10000005];
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    s[0]=1;
    for(int i=1;i<=10000000;i++)
    {
        s[i]=(1ll*s[i-1]*i)%mod;
    }
    cin>>t;
    while(t--)
    {
        cin>>n>>m>>k;
        if(m==0)
        {
            cout<<(1ll*s[n]*k)%mod<<'\n';
            continue;
        }
        int cnt=0;
        for(int i=1;i<=m/i;i++)
        {
            if(m%i!=0) continue;
            int t1=i,t2=m/i;
            if(t1<=n) cnt++;
            if(t2!=t1&&t2<=n) cnt++;
        }
        int t=(((1ll*n*(n+1))/2)%mod-k+mod)%mod;
        long long t2=((1ll*k*s[n-1])%mod*cnt)%mod+((1ll*t*s[n-2])%mod*(n-cnt))%mod;
        cout<<t2%mod<<"\n";
    }
    return 0;
}
